      { id: 242, text: "Nút lệnh 'Replace' (Thay thế) trong Word dùng để làm gì?", options: ["Để xóa tệp", "Để tìm và thay một từ bằng một từ khác tự động", "Để in văn bản", "Để lưu tệp"], correctAnswer: 1, explanation: "Giúp sửa lỗi hàng loạt cực kỳ nhanh chóng.", difficulty: "Hard", topic: "Ứng dụng tin học", type: "MCQ" },
      { id: 243, text: "Nối phím tắt với tính năng in ấn tài liệu:", pairs: [{ left: "Ctrl + P", right: "Mở cửa sổ In (Print)" }, { left: "F12", right: "Lưu tệp với tên khác (Save As)" }, { left: "Ctrl + S", right: "Lưu tệp đang làm" }], explanation: "Kỹ năng quản lý tệp và in ấn.", difficulty: "Medium", topic: "Ứng dụng tin học", type: "MATCHING" },
      { id: 244, text: "Trong Word, để thụt đầu dòng một đoạn văn nhanh, em nhấn phím nào trên bàn phím?", options: ["Space", "Tab", "Caps Lock", "Shift"], correctAnswer: 1, explanation: "Phím Tab giúp thụt lề chuẩn và đẹp.", difficulty: "Medium", topic: "Ứng dụng tin học", type: "MCQ" },
      { id: 245, text: "Em có thể chèn các hình khối (hình tròn, mũi tên, ngôi sao) vào Word được không?", options: ["Có", "Không"], correctAnswer: 0, explanation: "Sử dụng công cụ Shapes trong thẻ Insert.", difficulty: "Easy", topic: "Ứng dụng tin học", type: "TRUE_FALSE" },
      { id: 246, text: "Tìm lỗi sai trong danh sách các thẻ trên thanh Ribbon của Word/PowerPoint:", options: ["1. Home", "2. Insert", "3. Facebook", "4. Design"], correctAnswer: 2, errorPart: "Facebook", correction: "Facebook là mạng xã hội, không phải là một thẻ chức năng trong bộ Office.", explanation: "Nắm vững giao diện phần mềm.", difficulty: "Easy", topic: "Ứng dụng tin học", type: "FIND_ERROR" },
      { id: 247, text: "Để kiểm tra số trang và số từ trong Word, em nhìn vào thanh nào?", options: ["Thanh tiêu đề", "Thanh trạng thái (Status Bar) ở dưới cùng", "Thanh cuộn", "Thanh công cụ nhanh"], correctAnswer: 1, explanation: "Thanh trạng thái hiển thị các thông tin cơ bản về tài liệu.", difficulty: "Hard", topic: "Ứng dụng tin học", type: "MCQ" },
      { id: 248, text: "Lệnh 'Crop' trong Word dùng để làm gì khi xử lý hình ảnh?", options: ["Để nhân đôi hình ảnh", "Để cắt bỏ các phần dư thừa của ảnh", "Để làm ảnh mờ đi", "Để xóa ảnh"], correctAnswer: 1, explanation: "Cắt ảnh giúp tập trung vào nội dung chính.", difficulty: "Medium", topic: "Ứng dụng tin học", type: "MCQ" },
      { id: 249, text: "Nối loại phông chữ với đặc điểm của nó:", pairs: [{ left: "Times New Roman", right: "Phông có chân, nghiêm túc" }, { left: "Arial", right: "Phông không chân, hiện đại" }, { left: "Comic Sans", right: "Phông chữ nét vẽ tay, vui nhộn" }], explanation: "Lựa chọn phông chữ phù hợp với mục đích nội dung.", difficulty: "Hard", topic: "Ứng dụng tin học", type: "MATCHING" },
      { id: 250, text: "Khi làm Slide, em nên chọn màu chữ trùng với màu nền đúng hay sai?", options: ["Đúng", "Sai"], correctAnswer: 1, explanation: "Màu chữ và nền phải tương phản (ví dụ chữ đen trên nền trắng) để dễ đọc bài.", difficulty: "Easy", topic: "Ứng dụng tin học", type: "TRUE_FALSE" }
